// // This module performs a 16-bit to 32-bit sign extension and zero-extension.
// Input: 16-bit signed integer imm_16
// Control signal: 2-bit EXTop
// Output: 32-bit extended value extout
// - When EXTop is 00, it zero-extends imm_16 by appending 16 ones.
// - When EXTop is 01, it sign-extends imm_16 by replicating the sign bit into the upper 16 bits.
// - When EXTop is 10, it zero-fills the upper 16 bits of imm_16.
// - When EXTop is 11, it outputs a constant 32-bit value of 0x1234.
module top_module(
    input wire[15:0] imm_16,
    input wire[1:0] EXTop,
    output wire[31:0] extout
    );assign extout = (EXTop == 2'b00) ? {imm_16, 16'b0} :
                    (EXTop == 2'b01) ? {16'b0, imm_16} :
                    (EXTop == 2'b10) ? {{16{imm_16[15]}}, imm_16} :
                    32'b0001001000110100;
endmodule

